bitset<8005> del[8005], a[8005], b[8005];
void solve(int CASE)
{
	int n; cin >> n;
	fa(i, 1, n)del[i].reset(), b[i].reset(), a[i].reset();
	var ss = vector<string>(n + 1);
	fa(i, 1, n)cin >> ss[i], ss[i] = ' ' + ss[i];
	fa(i, 1, n)fa(j, 1, n) {
		if (ss[i][j] == '1')a[i][j] = 1;
		else a[i][j] = 0;
	}

	fa(i, 1, n)if (!a[i][i]) {
		cout << "No" << endl;
		return;
	}

	// floyd 检查冗余边（注意枚举顺序）
	fa(i, 1, n)a[i][i] = 0; // 排除自己到自己的影响
	fa(i, 1, n)fa(k, 1, n)if (a[i][k]) {
		del[i] |= a[k];
	}

	var p = vector<pii>();
	fa(i, 1, n)fa(j, 1, n)
		if (a[i][j] and !del[i][j])
			p.pb({ i,j });

	// 删掉冗余边，< n - 1 不连通，> n - 1 再也删不了边不满足条件
	if (p.size() != n - 1) {
		cout << "No" << endl;
		return;
	}

	// 并查集判定连通性
	var s = vector<int>(n + 1);
	fa(i, 1, n)s[i] = i;
	var find = [&](var find, int x)->int {
		if (s[x] == x)return x;
		return s[x] = find(find, s[x]);
		};
	for (const var& [x, y] : p) {
		int e1 = find(find, x), e2 = find(find, y);
		if (e1 != e2)s[e2] = e1;
	}
	var se = set<int>();
	fa(i, 1, n)se.insert(find(find, i));
	if (se.size() > 1) { // 不连通
		cout << "No" << endl;
		return;
	}

	// floyd 重构连通性数组，跟原数组进行验证（注意枚举顺序）
	for (const var& [x, y] : p)b[x][y] = 1;
	fa(k, 1, n)fa(i, 1, n)if (b[i][k])b[i] |= b[k];
	fa(i, 1, n)if (a[i] != b[i]) { // 与原数组不同
		cout << "No" << endl;
		return;
	}

	cout << "Yes" << endl;
	for (const var& [x, y] : p)cout << x << ' ' << y << endl;
	return;
}
